import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom'; // 1. Importar el navegador
import clienteAxios from '../api/axios';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate(); // 2. Inicializarlo

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const respuesta = await clienteAxios.post('/auth/login', { email, password });
            localStorage.setItem('token', respuesta.data.token);
            
            // 3. En lugar de solo el alert, navegamos a la despensa
            navigate('/productos'); 
        } catch (error) {
            alert('Error: ' + (error.response?.data?.message || 'Credenciales incorrectas'));
        }
    };

    return (
        <div style={{ padding: '20px', border: '1px solid #ddd', borderRadius: '10px', width: '300px', margin: 'auto' }}>
            <h2>Entrar a mi Despensa</h2>
            <form onSubmit={handleSubmit}>
                <input type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} style={inputStyle} />
                <input type="password" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} style={inputStyle} />
                <button type="submit" style={{ width: '100%', padding: '10px', background: '#28a745', color: 'white', border: 'none' }}>Iniciar Sesión</button>
            </form>
        </div>
    );
};

const inputStyle = { display: 'block', width: '90%', marginBottom: '15px', padding: '8px' };

export default Login;
